A = (sqrt(6)/2,sqrt(6)/2);
B = (sqrt(3),0);
C = (sqrt(6)/2,-sqrt(6)/2);

fill(A--B--C--cycle,gray(0.7));
draw(Circle((0,0),sqrt(3)));
draw((-2,0)--(2,0));
draw((0,-2)--(0,2));
draw(A--C);

for (i = 0; i <= 7; ++i) {
  dot(sqrt(3)*dir(45*i));
  draw(sqrt(3)*dir(45*i)--sqrt(3)*dir(45*(i + 1)));
}

