pen sm = fontsize(8); triple A = (.5,.5,1), B = (0,0,0), C = (1,0,0), D = (1,1,0), E = (0,1,0); /* should be A = (.5,.5,1/2^.5) */
draw(A--B--C--D--A--C); draw(A--E--D,linewidth(0.7)+linetype("3 3")); draw(B--E,linewidth(0.7)+linetype("2 2"));
label("A",A,N,sm); label("B",B,S,sm); label("C",C,S,sm);label("D",D,(1,0),sm);label("E",E,NW,sm); draw(B--D); label("$x$", (B+C)/2, SW); label("$x$", (C+D)/2, SE); label("$x\sqrt{2}$", (B+D)/2, N, sm); label("$\frac{x}{\sqrt{2}}$", (B+(B+D)/2)/2, N, sm); label("$x$",(A+B)/2, NW); draw(A--(B+D)/2);

[/asy]

