label("r",(i,3-i),N);
}
for (int i=0; i<3; ++i) {
label("g",(i,2-i),N);
}
for (int i=0; i<2; ++i) {
label("b",(i,1-i),N);
}
label("o",(0,0),N);
[/asy]

