draw((Circle((-5,.2),1)));
draw((Circle((-5.5,1.2-sqrt(3)),1)));
draw((Circle((-2,-0.3),1)));
draw((Circle((-2,0.3),1)));
draw((Circle((-.5,-0.3),1)));
draw((Circle((-.5,0.3),1)));

